section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/css-in-js-basics.json",
  "title": "CSS-in-JS Basics",
  "type": "object",
  "required": [
    "artefact_id",
    "library",
    "theme_provider_path",
    "primitive_paths",
    "convention_file_path",
    "owner",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "library": {
      "type": "string",
      "description": "styled-components | emotion | stitches | linaria | vanilla-extract | panda"
    },
    "theme_provider_path": {
      "type": "string",
      "minLength": 1
    },
    "primitive_paths": {
      "type": "array",
      "minItems": 1,
      "description": "list of primitive component paths"
    },
    "convention_file_path": {
      "type": "string",
      "minLength": 1,
      "description": "doc that codifies conventions"
    }
  },
  "additionalProperties": false
}
